// In CubeMX: Enable USART2, 115200 baud, 8N1
// Generated code in main.c:
UART_HandleTypeDef huart2;
huart2.Instance = USART2;
huart2.Init.BaudRate = 115200;
huart2.Init.WordLength = UART_WORDLENGTH_8B;
huart2.Init.StopBits = UART_STOPBITS_1;
huart2.Init.Parity = UART_PARITY_NONE;
huart2.Init.Mode = UART_MODE_TX_RX;
huart2.Init.HwFlowCtl = UART_HWCONTROL_NONE;
HAL_UART_Init(&huart2);

// Send:
HAL_UART_Transmit(&huart2, (uint8_t*)"Hello\n", 6, 100);
// Receive with DMA (recommended):
HAL_UART_Receive_DMA(&huart2, rx_buf, sizeof(rx_buf));
```
Enable USART2 clock in RCC. Configure GPIO pins (PA2=TX, PA3=RX) as AF7.

```c
// CubeMX: Enable I2C1, Standard Mode 100kHz
// Read single register:
uint8_t reg_addr = 0x0F; // WHO_AM_I
uint8_t data;
HAL_I2C_Mem_Read(&hi2c1, SENSOR_ADDR << 1, reg_addr, 
                  I2C_MEMADD_SIZE_8BIT, &data, 1, 100);

// Write register:
uint8_t config = 0x27; // enable XYZ axes
HAL_I2C_Mem_Write(&hi2c1, SENSOR_ADDR << 1, CTRL_REG1,
                   I2C_MEMADD_SIZE_8BIT, &config, 1, 100);
```
Note: HAL expects 8-bit address (shifted left by 1). Add 4.7k pull-ups on SDA/SCL. Check return value for HAL_OK.

