// CubeMX: TIM3 CH1, PWM Generation, 1kHz frequency
// APB1 = 84MHz, Prescaler = 83 -> 1MHz timer clock
// ARR (Period) = 999 -> 1kHz PWM
HAL_TIM_PWM_Start(&htim3, TIM_CHANNEL_1);

// Set duty cycle (0-100%):
void set_duty(uint8_t percent) {
    uint32_t pulse = (htim3.Init.Period + 1) * percent / 100;
    __HAL_TIM_SET_COMPARE(&htim3, TIM_CHANNEL_1, pulse);
}
// For complementary outputs (H-bridge): use TIM1 with dead-time
```
GPIO: Configure as AF (alternate function) for the timer channel.

```c
// CubeMX: TIM6, Internal Clock, Prescaler=83, Period=999
// -> 84MHz / (83+1) / (999+1) = 1kHz = 1ms interrupt
// Enable interrupt in NVIC
HAL_TIM_Base_Start_IT(&htim6);

void HAL_TIM_PeriodElapsedCallback(TIM_HandleTypeDef *htim) {
    if (htim->Instance == TIM6) {
        tick_1ms++;
        // Toggle LED every 500ms:
        if (tick_1ms % 500 == 0)
            HAL_GPIO_TogglePin(LED_GPIO_Port, LED_Pin);
    }
}
```
Note: SysTick is already used by HAL (1ms). Use a separate timer for your own timing to avoid conflicts.
